INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('promotion-d0d1b9a2-moex-00153', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '員山公司於X2年1月1日以$25,000,000取得一棟商業大樓，並分類為投資性不動產，採用公允 價值模式，並將商業大樓出租給鳳林公司，每年收取租金$1,200,000。X2年12月31日評估商業 大樓的公允價值為$23,600,000，但報稅上係以取得成本為課稅基礎，也不得將帳面金額調整至公 允價值，採直線法及按40年計提折舊，無殘值。員山公司X2年度的稅前淨利為$18,650,000，所 得稅率為20%，則X2年度綜合損益表上列報所得稅費用金額為何？', '["$3,575,000", "$3,855,000", "$3,730,000", "$3,015,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00154', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '康橋公司於 X5 年初付現$1,500,000 及開立 3 年期面額$3,000,000 的無息票據，購入機器設備一 部。機器設備估計耐用年限為5年，無殘值，採直線法提列折舊。當日市場利率為8%。若康橋公 司將機器設備誤以修理費用科目入帳，並於 X6 年初發現此項錯誤（康橋公司對應付票據的會計 處理並無錯誤），且假設X5年底保留盈餘之餘額為$320,000。試問X6年初保留盈餘之正確金額 為何（忽略所得稅的影響）？', '["$3,234,678", "$3,014,562", "$3,425,198", "$3,512,626"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00155', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-78566e18', 'sub-promotion-d0d1b9a2-01', NULL, 'single_choice', '苗栗公司於X4年初以完成3年的服務為條件，給與某位高階主管1項權利，可選擇取得相當於 既得日3,000股股票價值的現金或3,600股的股票，每股面值$10。若選擇取得股票，則於既得日 之後的兩年內不得出售。苗栗公司給與日的股價為每股$48，X4年、X5年及X6年底之股價分別 為$54、$51 及$57。考慮既得日後限制兩年內不得出售的效果，估計給與日限制權利股票的公允 價值為每股$45。試計算苗栗公司X5年度應認列之薪資費用為何？', '["$54,000", "$57,000", "$51,000", "$48,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:03+00:00", "source_pdf_sha1": "8b25447706f5", "answer_pdf_sha1": "ed2279a94aa6", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1003", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00156', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'essay', '政府會計採用固定項目劃分原則業已多年，但是「政府會計準則公報第
