  ('promotion-d0d1b9a2-moex-00159', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '依中央總會計制度規定，下列何者非屬公務機關應編製之財務報表？', '["資本資產表", "平衡表", "收入支出表", "平衡表科目明細表"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:04+00:00", "source_pdf_sha1": "58d6a158290d", "answer_pdf_sha1": "241f01d0d5c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00160', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '審計機關於查核甲機關補助乙直轄市政府之重大交通建設經費，發現甲機關已列支出之款項，乙 直轄市政府尚有部分款項雖已完工驗收，但未完成核銷付款，故減列甲機關支出實現數，並修正 改列應付數，試依中央政府普通公務單位會計制度之一致規定，審計機關修正甲機關時應為之完 整會計分錄？', '["借：預付款，貸：應付款項", "借：預付款，貸：資產負債淨額", "借：預付款，貸：公庫撥入數", "借：預付款，貸：繳付公庫數 12140"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:04+00:00", "source_pdf_sha1": "58d6a158290d", "answer_pdf_sha1": "241f01d0d5c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00161', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '甲機關經管之國有房舍於107年間發生火災，火勢迅速延燒鄰近民宅，民宅屋主向甲機關提出國 賠訴訟，截至107年底止，各種證據顯示，甲機關很有可能被判賠償$150,000，但108年底有新 證據顯示，被判賠償之可能性為40%，依中央政府普通公務單位會計制度之一致規定，請問甲機 關108年底應做何種會計分錄？', '["無須作分錄", "借：負債準備 150,000，貸：其他獎補捐助 150,000", "借：負債準備 150,000，貸：業務支出 150,000", "借：負債準備 150,000，貸：資產負債淨額 150,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:04+00:00", "source_pdf_sha1": "58d6a158290d", "answer_pdf_sha1": "241f01d0d5c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL),
  ('promotion-d0d1b9a2-moex-00162', 'promotion-d0d1b9a2', 'promotion-d0d1b9a2-moex-110-ac2adf20', 'sub-promotion-d0d1b9a2-02', NULL, 'single_choice', '依據甲機關單位決算會計報告顯示，其帳載預付款4,337 元、其他應收款31元、以前年度撥款於 本年度實現數6,734元、繳付公庫數54,844元、收入待納庫數4元、以前年度撥款於本年度繳還之 其他應收款2,478元，退還收入（預收）款80元、公庫撥入數42,470元，請問歲入實現數為何？', '["44,756元", "52,370元", "57,326元", "52,362元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:04+00:00", "source_pdf_sha1": "58d6a158290d", "answer_pdf_sha1": "241f01d0d5c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "120", "s": "1004", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "會計"}'::jsonb, NULL)
